extraExamples.hcl:
resource "awx_job_template" "ops_prompted" {
  name                    = "ops-prompted"
  job_type                = "run"
  project_id              = awx_project.ops.id
  playbook                = "operations.yml"
  ask_variables_on_launch = true
  ask_limit_on_launch     = true
  ask_tags_on_launch      = true
  extra_vars = {
    release_channel = "stable"
  }
}

primaryExample.hcl:
resource "awx_workflow_job_template" "release" {
  name            = "release-workflow"
  organization_id = awx_organization.platform.id
  survey_enabled  = true
  ask_variables_on_launch = true
  extra_vars = {
    release_track = "stable"
  }
}

extraExamples.hcl:
resource "awx_workflow_job_template" "from_gitlab" {
  name                  = "workflow-from-gitlab"
  organization_id       = awx_organization.platform.id
  webhook_service       = "gitlab"
  webhook_credential_id = awx_credential.gitlab_token.id
}

primaryExample.hcl:
data "awx_credential_type" "machine" {
  name = "Machine"
}

resource "awx_credential" "machine" {
  name               = "linux-ssh"
  credential_type_id = data.awx_credential_type.machine.id
  organization_id    = awx_organization.platform.id
  inputs = {
    username     = "ec2-user"
    ssh_key_data = var.machine_private_key
  }
}

extraExamples.hcl:
data "awx_credential_type" "scm" {
  name = "Source Control"
}

resource "awx_credential" "git_token" {
  name               = "git-token"
  credential_type_id = data.awx_credential_type.scm.id
  organization_id    = awx_organization.platform.id
  inputs = {
    username = "git"
    password = var.git_pat
  }
}

primaryExample.hcl:
resource "awx_inventory" "production" {
  name            = "production"
  organization_id = awx_organization.platform.id
  description     = "Primary production inventory"
}

extraExamples.hcl:
resource "awx_inventory" "linux_hosts" {
  name            = "linux-hosts"
  organization_id = awx_organization.platform.id
  kind            = "smart"
  host_filter     = "ansible_facts__os_family=RedHat"
}
